output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?label WHERE {
  wd:Q70891 rdfs:label ?label .
  FILTER(LANG(?label) = 'en')
}

args.sparql:
SELECT ?candidate ?candidateLabel ?votes WHERE {
  ?election wdt:P31 wd:Q41595;
            wdt:P176 wd:Q30;
            wdt:P2087 1824.
  ?election p:P2956 ?statement.
  ?statement ps:P2956 ?candidate.
  ?statement ps:P2337 ?votes.
  ?candidate rdfs:label ?candidateLabel.
  FILTER (LANG(?candidateLabel) = 'en')
} ORDER BY DESC(?votes) LIMIT 1

